<script>
import DataService from '../../services/DataService';
export default
    {
        props: {
            ProjectId: {
                type: Number,
                required: true,
            },
            TaskId: {
                type: Number,
                required: false,
            },
            Type: {
                type: String,
                required: true,
            },
            TabsArray: {
                type: String,
            },
            projectCurrency: {
                type: String,
            },
            TaskData: {
                type: Array || Object
            }
        },
        data() {
            return {
                txtTeamSearchPop: '',
                isLoading: false,
                GetTeamMemberData: [],
                teamData: [],
                projectTeams: [],
                MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
                FormSchemaaa: [
                    {
                        layoutType: "triple",
                        group_name: 'Add User Scroll',
                        Data: [
                            {
                                astype: "SelectField",
                                label: this.$t('Title'),
                                name: "Title",
                                value: "",
                                validationRules: { "required": false, max: 100 },
                                config: { options: [] }
                            },
                            {
                                astype: "SelectField",
                                label: this.$t('Gender'),
                                name: "Gender",
                                value: "",
                                validationRules: { "required": false, max: 4000 },
                                config: { options: [{ value: 'M', name: 'Male' }, { value: 'F', name: 'FeMale' }] }
                            },
                            {
                                astype: "TextField",
                                label: this.$t('FirstName'),
                                name: "FirstName",
                                value: "",
                                validationRules: { "required": true, max: 4000 },
                            },
                            {
                                astype: "TextField",
                                label: this.$t('LastName'),
                                name: "LastName",
                                value: "",
                                validationRules: { "required": true, max: 4000 },
                            },
                            {
                                astype: "TextField",
                                label: this.$t('Email'),
                                name: "Email",
                                value: "",
                                validationRules: { "required": true, max: 4000 },
                                config: { options: [] }
                            },
                            {
                                astype: "SelectField",
                                label: this.$t('UserType'),
                                name: "UserType",
                                value: "",
                                validationRules: { "required": true, max: 4000 },
                                config: { options: [] }
                            },
                            {
                                astype: "PasswordField",
                                label: this.$t('Password'),
                                name: "Password",
                                value: "",
                                validationRules: { "required": true, max: 4000 },
                            },
                            {
                                astype: "PasswordField",
                                label: this.$t('ConfirmPassword'),
                                name: "ConfirmPassword",
                                value: "",
                                validationRules: { "required": true, confirmed: true },
                                config: {
                                    onkeyup: this.ValidateConfirmPassword
                                },
                            },
                            {
                                astype: "SelectField",
                                label: this.$t('Role'),
                                name: "Role",
                                value: "",
                                validationRules: { "required": false, max: 4000 },
                                config: { options: [] }
                            },
                            {
                                astype: "SelectField",
                                label: this.$t('Department'),
                                name: "Department",
                                value: "",
                                validationRules: { "required": false, max: 4000 },
                                config: { options: [], onChange: this.GetAllPolicy }
                            },
                            {
                                astype: "DateField",
                                label: this.$t('Date of Hire (M/D/YYYY)'),
                                name: "DateofHire",
                                value: '',
                                placeholder: this.$t('StartDateTime'),
                                config: { format: "M/D/YYYY" }
                            },
                            {
                                astype: "SelectField",
                                label: this.$t('PolicyName'),
                                name: "PolicyName",
                                value: "",
                                validationRules: { "required": false, max: 4000 },
                                config: { options: [] }
                            },
                        ]
                    }
                ],
                buttonsss: [
                    {
                        type: "submit",
                        class: "btn btn-success",
                        text: "<i class='fa fa-save pr-2'></i>Save User",
                        onClick: this.SaveTeamMemberData
                    },
                    {
                        type: "button",
                        class: "btn btn-danger",
                        text: "<i class='fa fa-close pr-2'></i>Cancel",
                        onClick: this.Cancel
                    },
                ],
                userId: null,
                companyId: null,
                UserType: null,
                IsShowUser: false,
                updatecomponent: 0,
                teamType: 'user',
                sowuserempltyfiled: false,
                sowteamempltyfiled: false,
                isSaving: false,
                Currency: '',
                isValid: true,
                checkdecimalValue: false,
                projectName: '',
                dynamictabname: '',
                loginUserName: ''
            }
        },
        created: async function () {
            //debugger
            var ths = this;
            ths.Type == 'Project' ? ths.dynamictabname = 'Team' : ths.dynamictabname = ths.TabsArray[1];
            ths.projectName = ths.$route.params.projectName;
            ths.userId = ths.GetUserInfo.ID;
            ths.loginUserName = ths.GetUserInfo.Name;
            ths.companyId = ths.GetUserInfo.CompanyId;
            ths.UserType = ths.GetUserInfo.UserType;
            ths.Currency = ths.GetUserInfo.Currency.replace(/[()]/g, '');
            if (ths.teamType == "user") {
                await ths.FetchMemberListing();
            } else if (teamType == "team") {
                await ths.FetchTeamListing();
            }

        },
        computed: {
            validationRules() {
                return {
                    required: true,
                    regex: /^[a-zA-Z0-9\s]*$/,
                    max: 4,
                    decimalPlaces: 1
                };
            }
        },
        methods: {
            validateInput(event) {
                const char = String.fromCharCode(event.which || event.keyCode);
                const input = event.target;
                const value = input.value || '';
                const selectionStart = input.selectionStart || 0;
                const selectionEnd = input.selectionEnd || 0;

                // Allow backspace, delete, tab, escape, enter, arrow keys, home, end
                if ([8, 9, 27, 13, 46, 37, 38, 39, 40, 35, 36].indexOf(event.keyCode) !== -1 ||
                    // Allow Ctrl+A, Ctrl+C, Ctrl+V, Ctrl+X
                    (event.keyCode === 65 && event.ctrlKey === true) ||
                    (event.keyCode === 67 && event.ctrlKey === true) ||
                    (event.keyCode === 86 && event.ctrlKey === true) ||
                    (event.keyCode === 88 && event.ctrlKey === true)) {
                    return;
                }

                // Allow only numbers and decimal point
                if (!/[0-9.]/.test(char)) {
                    event.preventDefault();
                    return;
                }

                // Get the text that will result from this keypress
                const textBefore = value.substring(0, selectionStart);
                const textAfter = value.substring(selectionEnd);
                const newValue = textBefore + char + textAfter;

                // Check if decimal point already exists
                if (char === '.' && value.indexOf('.') !== -1) {
                    event.preventDefault();
                    return;
                }

                // Validate format: max 5 digits before decimal, max 2 after
                const parts = newValue.split('.');
                const beforeDecimal = parts[0] || '';
                const afterDecimal = parts[1] || '';

                // Prevent 6th digit before decimal
                if (beforeDecimal.length > 5) {
                    event.preventDefault();
                    return;
                }

                // Prevent 3rd digit after decimal
                if (afterDecimal.length > 2) {
                    event.preventDefault();
                    return;
                }

                this.isValid = true;
            },
            formatInput(event, member) {
                const input = event.target;
                let value = input.value;

                if (value === '' || value === null || value === undefined) {
                    member.ratePerHour = '';
                    this.isValid = true;
                    return;
                }

                // Convert to string
                value = String(value);

                // Remove any non-numeric characters except decimal point
                value = value.replace(/[^0-9.]/g, '');

                // Handle multiple decimal points - keep only the first one
                const decimalIndex = value.indexOf('.');
                if (decimalIndex !== -1) {
                    const before = value.substring(0, decimalIndex);
                    const after = value.substring(decimalIndex + 1).replace(/\./g, '');
                    value = before + '.' + after;
                }

                // Split by decimal point
                const parts = value.split('.');
                let beforeDecimal = parts[0] || '';
                let afterDecimal = parts[1] || '';

                // Limit to 5 digits before decimal - remove 6th digit or more
                if (beforeDecimal.length > 5) {
                    beforeDecimal = beforeDecimal.substring(0, 5);
                }

                // Limit to 2 digits after decimal - remove 3rd digit or more
                if (afterDecimal.length > 2) {
                    afterDecimal = afterDecimal.substring(0, 2);
                }

                // Reconstruct the value
                let formattedValue = beforeDecimal;
                const hadDecimal = value.indexOf('.') !== -1;
                if (hadDecimal) {
                    // If original value had decimal point, include it
                    formattedValue = beforeDecimal + '.' + afterDecimal;
                }

                // Update the model value (v-model will update the input)
                if (formattedValue === '' || formattedValue === '.') {
                    member.ratePerHour = '';
                } else {
                    member.ratePerHour = formattedValue;
                }

                // Validate - ensure format is correct (max 5 before, max 2 after)
                this.isValid = beforeDecimal.length <= 5 && afterDecimal.length <= 2;
            },
            handlePaste(event, member) {
                event.preventDefault();
                const pastedText = (event.clipboardData || window.clipboardData).getData('text');

                if (!pastedText) return;

                // Process pasted text through formatInput logic
                let value = String(pastedText);

                // Remove any non-numeric characters except decimal point
                value = value.replace(/[^0-9.]/g, '');

                // Handle multiple decimal points - keep only the first one
                const decimalIndex = value.indexOf('.');
                if (decimalIndex !== -1) {
                    const before = value.substring(0, decimalIndex);
                    const after = value.substring(decimalIndex + 1).replace(/\./g, '');
                    value = before + '.' + after;
                }

                // Split by decimal point
                const parts = value.split('.');
                let beforeDecimal = parts[0] || '';
                let afterDecimal = parts[1] || '';

                // Limit to 5 digits before decimal
                if (beforeDecimal.length > 5) {
                    beforeDecimal = beforeDecimal.substring(0, 5);
                }

                // Limit to 2 digits after decimal
                if (afterDecimal.length > 2) {
                    afterDecimal = afterDecimal.substring(0, 2);
                }

                // Reconstruct the value
                let formattedValue = beforeDecimal;
                if (value.indexOf('.') !== -1 && afterDecimal.length > 0) {
                    formattedValue = beforeDecimal + '.' + afterDecimal;
                }

                // Update the model value
                member.ratePerHour = formattedValue === '' ? '' : formattedValue;
                this.isValid = beforeDecimal.length <= 5 && afterDecimal.length <= 2;
            },
            async SaveAddTeams() {
                if (this.isSaving) return;

                this.isSaving = true;

                try {
                    await this.SaveAddTeam();
                } catch (err) {
                    console.error(err);
                } finally {
                    this.isSaving = false;
                }
            },
            restrictToNumbers(event) {
                const charCode = event.charCode || event.keyCode;
                const currentValue = event.target.value;
                if (
                    (charCode < 48 || charCode > 57) &&
                    charCode !== 46 &&
                    charCode !== 8 &&
                    charCode !== 9 &&
                    charCode !== 13
                ) {
                    event.preventDefault();
                }
                if (charCode === 46 && currentValue.indexOf('.') !== -1) {
                    event.preventDefault();
                }
                if (currentValue.includes('.') && currentValue.split('.')[1]?.length >= 2) {
                    if (charCode >= 48 && charCode <= 57) {
                        event.preventDefault();
                    }
                }
            },           
            FetchTeamListing: async function () {
               // debugger
                var ths = this;
                ths.isLoading = true;
                var refCode = "PROJECT";
                var refId = ths.ProjectId;
                if (this.TaskId > 0) {
                    refCode = "TASK";
                    refId = ths.TaskId;
                }
                var url = `refCode=${refCode}&refId=${refId}`;
                await DataService.GetTeamForAssociate(url).then((response) => {
                    ths.isLoading = false;
                    if (response.data != null && response.data.result.length > 0) {
                        let teams = response.data.result;
                        teams.forEach((x) => { x.isInSearch = true });
                        ths.teamData = teams;
                        ths.updatecomponent += 1;
                    }
                    else {
                        ths.sowteamempltyfiled = true;
                    }
                });
            },
            GetTeamOrUser: async function (type) {
              //  debugger
                var ths = this
                ths.teamType = type;
                ths.projectTeams=[];
                if (ths.teamType == "user") {
                    await ths.FetchMemberListing();
                } else if (ths.teamType == "team") {
                    await ths.FetchTeamListing();
                }
            },
            ValidateConfirmPassword() {
                var vm = this;
                var getPasswordvalue = undefined;
                var getConfirmPasswordvalue = undefined;
                vm.FormSchemaaa.forEach(item => {
                    item.Data.forEach(x => {
                        if (x.name == "Password") {
                            getPasswordvalue = x;
                        } else if (x.name == "ConfirmPassword") {
                            getConfirmPasswordvalue = x;
                        }
                    })
                })
                if (getPasswordvalue && getConfirmPasswordvalue != undefined) {
                    if (getPasswordvalue.value == getConfirmPasswordvalue.value) {
                        getConfirmPasswordvalue.validationRules = {
                            "confirmed": false,
                            "required": true
                        }
                    } else {
                        getConfirmPasswordvalue.validationRules = {
                            "confirmed": true,
                            "required": true
                        }
                    }
                }
            },
            Close() {
                this.$emit("close");
            },
            FetchMemberListing: async function () {
                var ths = this;
                ths.isLoading = true;
                ths.GetTeamMemberData = [];
                var url = `search=PROJECT&projectId=${ths.ProjectId}`
                if (ths.TaskId > 0) {
                    url += "&taskId=" + ths.TaskId;
                }
                await DataService.AddMemberInProject(url).then((response) => {
                    //debugger
                    if (response.data.length > 0) {
                        var data = response.data;

                        data.forEach(item => {
                            item.ShowAliasName = true;
                            item.ShowIsPM = true;
                            item.CheckAliasName = false;
                            item.CheckIsName = false;
                            ths.isLoading = false;
                            item.isInSearch = true;
                        });
                        ths.GetTeamMemberData = data;
                        ths.updatecomponent += 1;
                    } else {
                        ths.sowuserempltyfiled = true;
                        ths.isLoading = false;
                    }
                });
            },
            OpenAddUserModal: function () {
                var vm = this;
                vm.IsShowUser = true;
                vm.GetUserTitile();
                vm.GetUserDepatment();
                vm.GetUserTypes();
                vm.GetAllRolesOfUserType();
            },
            GetUserTitile: function () {
                var ths = this;
                DataService.GetUserTitle().then(async (response) => {
                    if (response.data.length > 0) {
                        response.data.forEach((element) => {
                            var obj = {
                                value: element.user_title_id,
                                name: element.user_title
                            }
                            ths.FormSchemaaa[0].Data[0].config.options.push(obj);
                        })
                        ths.$refs.AddTeamForm.UpdateKeyValue();
                    }
                });
            },
            GetUserDepatment: function () {
                var ths = this;
                DataService.GetUserDepatment().then(async (response) => {
                    if (response.data.length > 0) {
                        response.data.forEach((element) => {
                            var obj = {
                                value: element.department_id,
                                name: element.department_name
                            }
                            ths.FormSchemaaa[0].Data[9].config.options.push(obj);
                            ths.$refs.AddTeamForm.UpdateKeyValue();
                        })
                    }
                });
            },
            GetUserTypes() {
                var ths = this;
                var params = `filterby=MANAGEUSER`;
                DataService.GetUserTypes(params).then(async (response) => {
                    if (response.data.length > 0) {
                        response.data.forEach((element) => {
                            var obj = {
                                value: element.USER_TYPE_ID,
                                name: element.USER_TYPE_DESC
                            }
                            ths.FormSchemaaa[0].Data[5].config.options.push(obj);
                            ths.$refs.AddTeamForm.UpdateKeyValue();
                        })
                    }
                });
            },
            GetAllRolesOfUserType: function () {
                var ths = this;
                var params = `userType=3`;
                DataService.GetAllRolesOfUserType(params).then(async (response) => {
                    if (response.data.length > 0) {
                        response.data.forEach((element) => {
                            var obj = {
                                value: element.role_id,
                                name: element.role_name
                            }
                            ths.FormSchemaaa[0].Data[8].config.options.push(obj);
                            ths.$refs.AddTeamForm.UpdateKeyValue();
                        })
                    }
                });
            },
            GetAllPolicy: function (x, y, z) {
                var ths = this;
                var params = `departmentId=${y.value}`;
                DataService.GetAllPolicy(params).then(async (response) => {
                    if (response.data.length > 0) {
                        response.data.forEach((element) => {
                            var obj = {
                                value: element.ID,
                                name: element.POLICY_NAME
                            }
                            ths.FormSchemaaa[0].Data[11].config.options.push(obj);
                            ths.$refs.AddTeamForm.UpdateKeyValue();
                        })
                    }
                });
            },
            SaveTeamMemberData: function () {
                debugger
                var ths = this;
                var VarObject = {
                    FirstName: ths.FormSchemaaa[0].Data[2].value,
                    LatName: ths.FormSchemaaa[0].Data[3].value,
                    Email: ths.FormSchemaaa[0].Data[4].value,
                    UserType: ths.FormSchemaaa[0].Data[5].value,
                    Role: ths.FormSchemaaa[0].Data[8].value,
                    Department: ths.FormSchemaaa[0].Data[9].value,
                    Password: ths.FormSchemaaa[0].Data[6].value,
                    Title: ths.FormSchemaaa[0].Data[0].value,
                    Gender: ths.FormSchemaaa[0].Data[1].value,
                    UserDate: ths.FormSchemaaa[0].Data[10].value,
                    Policy: ths.FormSchemaaa[0].Data[11].value,
                }
                debugger
                var objectPostString = JSON.stringify(VarObject);
                DataService.SavedUser(objectPostString).then(function (response) {
                    if (response.data.msg == 'Add') {
                        ths.ShowAlert(ths.$t('AddedSuccess', [ths.$t('User')]), "success", true, ths.$t("Alert"));
                        ths.Cancel();
                        ths.$emit('callbackfunction');
                    }
                    else {
                        ths.ShowAlert(ths.$t('UnknownErrorOccur'), "failure", true, ths.$t("Alert"));
                    }
                });

            },
            Cancel: function () {
                var vm = this;
                vm.IsShowUser = false;
            },
            checkboxAlias: function (evt, item) {                
                var vm = this;
                if (evt.target.checked) {
                    this.GetTeamMemberData = this.GetTeamMemberData.map(itm =>
                        itm.USER_ID === item.USER_ID ? { ...itm, CheckAliasName: true } : itm
                    );
                } else {
                    this.GetTeamMemberData = this.GetTeamMemberData.map(itm =>
                        itm.USER_ID === item.USER_ID ? { ...itm, CheckAliasName: false } : itm
                    );
                }
            },
            checkIsName: function (evt, item) {
                var vm = this;
                if (evt.target.checked) {
                    this.GetTeamMemberData = this.GetTeamMemberData.map(itm =>
                        itm.USER_ID === item.USER_ID ? { ...itm, CheckIsName: true } : itm
                    );
                } else {
                    this.GetTeamMemberData = this.GetTeamMemberData.map(itm =>
                        itm.USER_ID === item.USER_ID ? { ...itm, CheckIsName: false } : itm
                    );
                }
            },
            checkboxidds(evt, item) {
               // debugger
                var vm = this;                
                if (evt.target.checked) {
                    this.GetTeamMemberData = this.GetTeamMemberData.map(itm =>
                        itm.USER_ID === item.USER_ID ? { ...itm, ShowAliasName: false } : itm
                    );
                    this.GetTeamMemberData = this.GetTeamMemberData.map(itm =>
                        itm.USER_ID === item.USER_ID ? { ...itm, ShowIsPM: false } : itm
                    );
                    vm.projectTeams.push(item);
                }
                else {
                    this.GetTeamMemberData = this.GetTeamMemberData.map(itm =>
                        itm.USER_ID === item.USER_ID ? { ...itm, ShowAliasName: true } : itm
                    );
                    this.GetTeamMemberData = this.GetTeamMemberData.map(itm =>
                        itm.USER_ID === item.USER_ID ? { ...itm, ShowIsPM: true } : itm
                    );
                    this.GetTeamMemberData = this.GetTeamMemberData.map(itm =>
                        itm.USER_ID === item.USER_ID ? { ...itm, CheckAliasName: false } : itm
                    );
                    this.GetTeamMemberData = this.GetTeamMemberData.map(itm =>
                        itm.USER_ID === item.USER_ID ? { ...itm, CheckIsName: false } : itm
                    );
                    const index = vm.projectTeams.findIndex(team => team.USER_ID == item.USER_ID);
                    if (index !== -1) {
                        vm.projectTeams.splice(index, 1);
                    }
                    document.getElementById("chkAll_28").checked = false;
                }
                var allCheckboxes = document.getElementsByClassName("custom-control-input addmem checkboxid");
                var checkedCheckboxes = [...allCheckboxes].filter(cb => cb.checked);

                if (allCheckboxes.length > 0 && allCheckboxes.length === checkedCheckboxes.length) {
                    document.getElementById("chkAll_28").checked = true;
                } else {
                    document.getElementById("chkAll_28").checked = false;
                }

            },
            SelectteamAllChekcboxes(evt) {
                var vm = this;
                var checkedarray = document.getElementsByClassName("custom-control-input addmem checkboxid");
                if (evt.target.checked) {
                    for (var i = 0; i < checkedarray.length; i++) {
                        checkedarray[i].checked = true;
                        vm.projectTeams.push({ TEAM_ID: checkedarray[i].value });
                    }
                } else {
                    for (var i = 0; i < checkedarray.length; i++) {
                        checkedarray[i].checked = false;
                    }
                    vm.projectTeams = [];
                }
            },
            SelectAllChekcboxes(evt) {
               // debugger
                var vm = this;
                var checkedarray = document.getElementsByClassName("custom-control-input addmem checkboxid");
                if (evt.target.checked) {
                    for (var i = 0; i < checkedarray.length; i++) {
                        checkedarray[i].checked = true;
                        this.GetTeamMemberData = this.GetTeamMemberData.map(itm =>
                            itm.USER_ID === parseInt(checkedarray[i].value) ? { ...itm, ShowAliasName: false } : itm
                        );
                        this.GetTeamMemberData = this.GetTeamMemberData.map(itm =>
                            itm.USER_ID === parseInt(checkedarray[i].value) ? { ...itm, ShowIsPM: false } : itm
                        );
                        vm.projectTeams.push(this.GetTeamMemberData[i]);
                    }

                } else {
                    for (var i = 0; i < checkedarray.length; i++) {
                        checkedarray[i].checked = false;
                        this.GetTeamMemberData = this.GetTeamMemberData.map(itm =>
                            itm.USER_ID === parseInt(checkedarray[i].value) ? { ...itm, ShowAliasName: true } : itm
                        );
                        this.GetTeamMemberData = this.GetTeamMemberData.map(itm =>
                            itm.USER_ID === parseInt(checkedarray[i].value) ? { ...itm, ShowIsPM: true } : itm
                        );
                        vm.projectTeams.push(this.GetTeamMemberData[i]);
                    }
                    vm.projectTeams = [];
                }
            },
            SetAliasName: function (item) {
                var ths = this;
              //  debugger
                const matched = ths.GetTeamMemberData.find(itm => itm.USER_ID === item.USER_ID);
                if (matched) {
                    matched.ALIASNAME = item.ALIASNAME;
                }
            },
            SaveAddTeam: async function () {
                debugger
                var ths = this;
                var val = '';
                var FinalTeam = [];
                var notificationArray = [];
                if (ths.projectTeams.length == 0) {
                    ths.ShowAlert(ths.$t('selectteamuser'), "warning", true, ths.$t("Alert"));
                    return false;
                }
                else {
                    if (ths.teamType == "user") {
                        ths.projectTeams.forEach((itm) => {
                            var Obj = {
                                projectId: ths.ProjectId,
                                taskId: (ths.TaskId > 0 ? ths.TaskId : null),
                                UserId: itm.USER_ID,
                                RatePerHours: itm.ratePerHour,
                                // UserTypeId:itm.USER_TYPE_ID,
                                IsPM: itm.ShowIsPM == true ? 1 : 0,
                                UserTypeId: itm.ShowIsPM == true ? 2 : itm.USER_TYPE_ID,
                                iSShowAliasNam: itm.ShowAliasName == true ? 1 : 0,
                                ALIASNAME: itm.ALIASNAME
                            }
                            FinalTeam.push(Obj)
                            notificationArray.push({
                                user_id: Obj.UserId,
                                sold_horly_rate: Obj.RatePerHours,
                                designation_id: null,
                                user_type_id: 1,
                                alias_name: Obj.ALIASNAME,
                                is_show_alias: Obj.iSShowAliasNam,
                                status_id: 1001
                            });
                        });
                    } 
                    else {
                        ths.projectTeams.forEach((itm) => {
                            var Obj = {
                                projectId: ths.ProjectId,
                                taskId: (ths.TaskId > 0 ? ths.TaskId : null),
                                UserId: itm.TEAM_ID,
                                RatePerHours: null,
                                UserTypeId: null,
                                IsPM: 0,
                                iSShowAliasNam: null,
                                ALIASNAME: null
                            }
                            FinalTeam.push(Obj)
                            notificationArray.push({
                                team_id: itm.TEAM_ID,
                                status_id: 1001,
                                user_type_id: null,
                            });
                        });
                    }
                }
                var data = { Data: FinalTeam, teamType: ths.teamType, refCode: (ths.TaskId > 0 ? 'TASK' : 'PROJECT') };               
                let payload = {
                    projectId: ths.ProjectId,
                    projectName: 'text',
                    projectContent: notificationArray[0].user_type_id == null ? `Team added by ${ths.loginUserName}` : ths.IsType == 'Task' ? `${ths.TaskData.task_name} ${ths.$t('taskassignedtoyou')} ${ths.$d(new Data(ths.TaskData.planned_end_date))}` : `${this.$t('assignedanewproject')} ${this.loginUserName}`,
                    projectTeam: notificationArray
                };
                debugger               
                var objectPostString = JSON.stringify(data);
                await DataService.SaveAddTeam(objectPostString).then((response) => {
                    if (response.data.result.length > 0) {
                        ths.ShowAlert(ths.$t('AddedSuccess', [ths.$t(ths.TabsArray[1])]), "success", true, ths.$t("Alert"));
                        ths.Close();
                        ths.$emit('callbackfunction');

                        DataService.SendAddProjectNotification(JSON.stringify(payload)).then((res) => {
                            console.log("Notification Response:", res.data);
                        });
                    }
                });
            },
            SearchTeam_Add() {
                //debugger
                var search = this.txtTeamSearchPop.toLowerCase();
                if (this.teamType == "team") {
                   // debugger
                    this.teamData.forEach((x) => {
                        x.isInSearch = true;
                       // debugger
                        if (!x.TEAM_NAME.toLowerCase().includes(search)) {
                            x.isInSearch = false;
                            this.sowteamempltyfiled = true;
                        }
                    })
                } else if (this.teamType == "user") {
                    //debugger
                    this.GetTeamMemberData.forEach((x) => {
                       // debugger
                        x.isInSearch = true;
                        if (!x.MEMBERNAME.toLowerCase().includes(search)) {
                            x.isInSearch = false;
                            this.sowuserempltyfiled = true;
                        }

                    })
                }
            },
            clearTeam_add() {
                this.sowuserempltyfiled = false;
                this.sowteamempltyfiled = false;
                this.txtTeamSearchPop = '';
                this.GetTeamMemberData = [];
                this.FetchMemberListing();
                this.FetchTeamListing();
            }
        }
    }
</script>
